  const parsedUrl = new URL(url);
  const { hostname, pathname, search, hash } = parsedUrl;

  // Check if the URL contains a username and password
  if (parsedUrl.username && parsedUrl.password) {
    // Reconstruct the URL without username and password
    const strippedUrl = `${hostname}${pathname}${search}${hash}`;
    return strippedUrl;
  } else {
    // If the URL doesn't contain a username and password, return the original URL
    return url;
  }
}

