I'll provide a Python implementation using the Kneser-Ney smoothing algorithm for language modeling. We'll use the NLTK library for tokenization and the math library for mathematical operations.

```python
import math
import nltk
from nltk.tokenize import word_tokenize
from collections import defaultdict

# Download required NLTK data
nltk.download('punkt')

class LanguageModel:
    def __init__(self, train_data):
        self.train_data = train_data
        self.word_freq = self._calculate_word_freq()
        self.total_words = sum(self.word_freq.values())

    def _calculate_word_freq(self):
        word_freq = defaultdict(int)
        for sentence in self.train_data:
            words = word_tokenize(sentence)
            for word in words:
                word_freq[word] += 1
        return word_freq

    def _calculate_bigram_freq(self):
        bigram_freq = defaultdict(int)
        for i in range(len(self.train_data) - 1):
            words = word_tokenize(self.train_data[i])
            next_words = word_tokenize(self.train_data[i + 1])
            for j in range(len(words)):
                if j + 1 < len(next_words):
                    bigram_freq[(words[j], next_words[j])] += 1

